import React, { useState, useEffect } from 'react';
import { View, Text, Button, Alert } from 'react-native';

const TokenGenerator = () => {
  const [token, setToken] = useState(null);
  const [isOffline, setIsOffline] = useState(false);

  useEffect(() => {
    const handleConnectivityChange = () => {
      const online = navigator.onLine;
      setIsOffline(!online);
      if (!online) {
        generateToken();
      }
    };

    window.addEventListener('online', handleConnectivityChange);
    window.addEventListener('offline', handleConnectivityChange);

    return () => {
      window.removeEventListener('online', handleConnectivityChange);
      window.removeEventListener('offline', handleConnectivityChange);
    };
  }, []);

  const generateToken = () => {
    const newToken = Math.random().toString(36).substr(2, 9);
    setToken(newToken);
    Alert.alert('Offline Mode', `New token generated: ${newToken}`);
  };

  return (
    <View style={{ padding: 20 }}>
      <Text>Current Token: {token || 'No token generated'}</Text>
      <Text>Status: {isOffline ? 'Offline' : 'Online'}</Text>
      <Button title="Generate Token" onPress={generateToken} />
    </View>
  );
};

export default TokenGenerator;